import{_ as a,o as i,c as t,ai as l}from"./chunks/framework.DKRJm8HN.js";const p=JSON.parse('{"title":"Examples","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"examples/index.md","filePath":"examples/index.md"}'),r={name:"examples/index.md"};function o(s,e,n,d,m,h){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to “Examples”">​</a></h1><p>This section showcases different editor configurations and use cases built with vue-quilly. Each example demonstrates specific features and integration patterns you can use in your projects.</p><h2 id="available-examples" tabindex="-1">Available Examples <a class="header-anchor" href="#available-examples" aria-label="Permalink to “Available Examples”">​</a></h2><h3 id="snow-theme-editor" tabindex="-1"><a href="/examples/snow-theme.html">Snow Theme Editor</a> <a class="header-anchor" href="#snow-theme-editor" aria-label="Permalink to “Snow Theme Editor”">​</a></h3><p>The classic Quill editor with the Snow theme, featuring a full toolbar with all formatting options.</p><p><strong>Features:</strong></p><ul><li>Complete toolbar with all formatting options</li><li>Formula support with KaTeX</li><li>Image and video embedding</li><li>Font, size, and color customization</li></ul><h3 id="bubble-theme-editor" tabindex="-1"><a href="/examples/bubble-theme.html">Bubble Theme Editor</a> <a class="header-anchor" href="#bubble-theme-editor" aria-label="Permalink to “Bubble Theme Editor”">​</a></h3><p>Lightweight editor with the Bubble theme that shows toolbar on text selection.</p><p><strong>Features:</strong></p><ul><li>Medium-style inline toolbar</li><li>Appears on text selection</li><li>Same formatting capabilities as Snow theme</li><li>Cleaner, more minimalist interface</li></ul><h3 id="semantic-html-editor" tabindex="-1"><a href="/examples/semantic-html.html">Semantic HTML Editor</a> <a class="header-anchor" href="#semantic-html-editor" aria-label="Permalink to “Semantic HTML Editor”">​</a></h3><p>Editor configured to output clean, semantic HTML without Quill-specific classes.</p><p><strong>Features:</strong></p><ul><li>Clean HTML output (e.g., <code>&lt;h1&gt;</code> instead of <code>&lt;p class=&quot;ql-header-1&quot;&gt;</code>)</li><li>Better for SEO and accessibility</li><li>Easy content portability</li><li>Ideal for CMS and blog posts</li></ul><h3 id="image-resize-editor" tabindex="-1"><a href="/examples/image-resize.html">Image Resize Editor</a> <a class="header-anchor" href="#image-resize-editor" aria-label="Permalink to “Image Resize Editor”">​</a></h3><p>Editor with image resize functionality using the <code>quill-image-resize-module</code>.</p><p><strong>Features:</strong></p><ul><li>Drag to resize images</li><li>Display size indicator</li><li>Resize handles on images</li><li>Image alignment toolbar</li></ul><h3 id="custom-editor-core-build" tabindex="-1"><a href="/examples/custom-editor.html">Custom Editor (Core Build)</a> <a class="header-anchor" href="#custom-editor-core-build" aria-label="Permalink to “Custom Editor (Core Build)”">​</a></h3><p>Minimal custom editor using <code>quill/core</code> with only specific blots registered.</p><p><strong>Features:</strong></p><ul><li>Minimal bundle size (uses <code>quill/core</code>)</li><li>Custom blots (Bold, Italic, Headers)</li><li>External toolbar controls</li><li>Perfect for custom implementations</li></ul><h2 id="live-demo" tabindex="-1">Live Demo <a class="header-anchor" href="#live-demo" aria-label="Permalink to “Live Demo”">​</a></h2><p>Try all these examples live at <a href="https://vue-quilly.vercel.app/" target="_blank" rel="noreferrer">vue-quilly.vercel.app</a></p><h2 id="source-code" tabindex="-1">Source Code <a class="header-anchor" href="#source-code" aria-label="Permalink to “Source Code”">​</a></h2><p>View the complete source code for all examples in our <a href="https://github.com/alekswebnet/vue-quilly/tree/main/demo" target="_blank" rel="noreferrer">demo directory</a>.</p><h2 id="integration-examples" tabindex="-1">Integration Examples <a class="header-anchor" href="#integration-examples" aria-label="Permalink to “Integration Examples”">​</a></h2><ul><li><a href="https://github.com/alekswebnet/vue-quilly/tree/main/nuxt" target="_blank" rel="noreferrer">Nuxt 4 Integration</a> - SSR setup with Nuxt</li><li><a href="https://codepen.io/redrobot753/pen/VwJwPLP" target="_blank" rel="noreferrer">Browser CDN Setup</a> - CodePen example</li></ul>',29)])])}const u=a(r,[["render",o]]);export{p as __pageData,u as default};
